import{_ as e,c as r,o as t,ah as o}from"./chunks/framework.Cnj7lwEt.js";const p=JSON.parse('{"title":"项目名称","description":"","frontmatter":{},"headers":[],"relativePath":"github汇总/运维工具/KubePrometheus-运维工具.md","filePath":"github汇总/运维工具/KubePrometheus-运维工具.md"}'),n={name:"github汇总/运维工具/KubePrometheus-运维工具.md"};function s(l,a,i,h,d,c){return t(),r("div",null,a[0]||(a[0]=[o('<h1 id="项目名称" tabindex="-1">项目名称 <a class="header-anchor" href="#项目名称" aria-label="Permalink to “项目名称”">​</a></h1><p>kube-prometheus</p><h1 id="作者或组织名" tabindex="-1">作者或组织名 <a class="header-anchor" href="#作者或组织名" aria-label="Permalink to “作者或组织名”">​</a></h1><p>Prometheus Operator</p><h1 id="项目类别" tabindex="-1">项目类别 <a class="header-anchor" href="#项目类别" aria-label="Permalink to “项目类别”">​</a></h1><p>运维工具</p><h1 id="核心痛点" tabindex="-1">核心痛点 <a class="header-anchor" href="#核心痛点" aria-label="Permalink to “核心痛点”">​</a></h1><p>Kubernetes集群监控配置复杂、组件管理困难、缺少完整的端到端解决方案</p><h1 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to “主要功能”">​</a></h1><ul><li>使用Prometheus Operator的端到端Kubernetes集群监控</li><li>收集Grafana仪表板和Prometheus规则</li><li>使用Jsonnet的声明式配置</li></ul><h1 id="项目亮点" tabindex="-1">项目亮点 <a class="header-anchor" href="#项目亮点" aria-label="Permalink to “项目亮点”">​</a></h1><ul><li>Prometheus官方项目，质量可靠</li><li>端到端解决方案，开箱即用</li><li>声明式配置，易于管理</li><li>集成Grafana仪表板</li><li>社区维护，持续更新</li></ul><h1 id="荣誉信息" tabindex="-1">荣誉信息 <a class="header-anchor" href="#荣誉信息" aria-label="Permalink to “荣誉信息”">​</a></h1><p>README/仓库信息中未明确说明</p><h1 id="项目地址" tabindex="-1">项目地址 <a class="header-anchor" href="#项目地址" aria-label="Permalink to “项目地址”">​</a></h1><p><a href="https://github.com/prometheus-operator/kube-prometheus" target="_blank" rel="noreferrer">https://github.com/prometheus-operator/kube-prometheus</a> <a href="/网络环境.html">海外网络环境配置 →</a></p><h1 id="安装或部署教程" tabindex="-1">安装或部署教程 <a class="header-anchor" href="#安装或部署教程" aria-label="Permalink to “安装或部署教程”">​</a></h1><h2 id="教程适用对象与环境范围" tabindex="-1">教程适用对象与环境范围 <a class="header-anchor" href="#教程适用对象与环境范围" aria-label="Permalink to “教程适用对象与环境范围”">​</a></h2><p>适用于想要在Kubernetes集群中部署完整监控解决方案的运维人员，需要Kubernetes集群环境。</p><h2 id="前置条件检查" tabindex="-1">前置条件检查 <a class="header-anchor" href="#前置条件检查" aria-label="Permalink to “前置条件检查”">​</a></h2><ol><li>系统要求：已运行的Kubernetes集群（1.29或更高版本）</li><li>工具要求：kubectl正确配置连接到集群</li><li>存储要求：集群中有可用的持久卷或StorageClass（可选）</li></ol><h2 id="主路径-快速部署-推荐新手" tabindex="-1">主路径：快速部署（推荐新手） <a class="header-anchor" href="#主路径-快速部署-推荐新手" aria-label="Permalink to “主路径：快速部署（推荐新手）”">​</a></h2><h3 id="步骤1-创建命名空间和crds" tabindex="-1">步骤1：创建命名空间和CRDs <a class="header-anchor" href="#步骤1-创建命名空间和crds" aria-label="Permalink to “步骤1：创建命名空间和CRDs”">​</a></h3><p><strong>步骤目标</strong>：创建监控命名空间和Prometheus Operator的CRDs <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：运行 <code>kubectl apply --server-side -f manifests/setup/</code><strong>成功标志</strong>：资源创建成功 <strong>失败处理</strong>：检查kubectl配置是否正确，集群是否正常</p><h3 id="步骤2-等待crds建立" tabindex="-1">步骤2：等待CRDs建立 <a class="header-anchor" href="#步骤2-等待crds建立" aria-label="Permalink to “步骤2：等待CRDs建立”">​</a></h3><p><strong>步骤目标</strong>：确认CRDs在API服务器中建立 <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：运行 <code>until kubectl get servicemonitors --all-namespaces ; do date; sleep 1; echo &quot;&quot;; done</code><strong>成功标志</strong>：能够列出ServiceMonitors <strong>失败处理</strong>：检查集群状态</p><h3 id="步骤3-部署监控堆栈" tabindex="-1">步骤3：部署监控堆栈 <a class="header-anchor" href="#步骤3-部署监控堆栈" aria-label="Permalink to “步骤3：部署监控堆栈”">​</a></h3><p><strong>步骤目标</strong>：部署完整的监控组件 <strong>执行位置</strong>：命令行终端 <strong>完整命令或操作</strong>：运行 <code>kubectl apply -f manifests/</code><strong>成功标志</strong>：所有资源部署成功 <strong>失败处理</strong>：查看Pod日志排查问题</p><h3 id="步骤4-访问grafana" tabindex="-1">步骤4：访问Grafana <a class="header-anchor" href="#步骤4-访问grafana" aria-label="Permalink to “步骤4：访问Grafana”">​</a></h3><p><strong>步骤目标</strong>：访问Grafana仪表板 <strong>执行位置</strong>：浏览器 <strong>完整命令或操作</strong>：运行 <code>kubectl --namespace monitoring port-forward svc/grafana 3000</code>，然后访问 <a href="http://localhost:3000" target="_blank" rel="noreferrer">http://localhost:3000</a><strong>成功标志</strong>：Grafana登录页面显示 <strong>失败处理</strong>：确认端口转发正常</p><h2 id="安装成功验证" tabindex="-1">安装成功验证 <a class="header-anchor" href="#安装成功验证" aria-label="Permalink to “安装成功验证”">​</a></h2><p>所有Pod正常运行，能够访问Prometheus、Alertmanager和Grafana界面。</p><h2 id="常见错误排查" tabindex="-1">常见错误排查 <a class="header-anchor" href="#常见错误排查" aria-label="Permalink to “常见错误排查”">​</a></h2><ol><li><p><strong>现象</strong>：Pod处于Pending状态</p><ul><li><strong>可能原因</strong>：缺少可用节点或存储</li><li><strong>解决步骤</strong>：检查节点资源和持久卷配置</li></ul></li><li><p><strong>现象</strong>：无法访问监控界面</p><ul><li><strong>可能原因</strong>：Service类型或端口转发问题</li><li><strong>解决步骤</strong>：使用NodePort或LoadBalancer暴露服务，或正确配置端口转发</li></ul></li><li><p><strong>现象</strong>：指标收集失败</p><ul><li><strong>可能原因</strong>：RBAC权限或ServiceMonitor配置</li><li><strong>解决步骤</strong>：检查RBAC配置和ServiceMonitor选择器</li></ul></li></ol><h2 id="备选部署路径-自定义配置" tabindex="-1">备选部署路径：自定义配置 <a class="header-anchor" href="#备选部署路径-自定义配置" aria-label="Permalink to “备选部署路径：自定义配置”">​</a></h2><p>如需要自定义配置，可参考README中的Jsonnet配置指南。</p><h2 id="信息缺失说明" tabindex="-1">信息缺失说明 <a class="header-anchor" href="#信息缺失说明" aria-label="Permalink to “信息缺失说明”">​</a></h2><p>README提供了完整的部署指引，但高级自定义配置需要参考进一步的文档。</p>',38)]))}const b=e(n,[["render",s]]);export{p as __pageData,b as default};
